+    /// Get or create Q2_K tensor buffer through ExpertCache (lazy-load)
+    /// This is the memory-safe version that uses LRU cache instead of bulk loading
+    pub fn getOrCreateHybridQ2KBuffer(self: *Self, tensor_name: []const u8) !objc.MTLBuffer {
+        // Not in cache - load from Q2_K mmap
+        const mmap_ptr = self.hybrid_q2k_mmap_ptr orelse return error.HybridQ2KNotConfigured;
+        const info = self.getHybridQ2KTensorInfo(tensor_name) orelse return error.TensorNotFound;
+
+        // Get pointer to tensor data in mmap
+        const data_ptr = mmap_ptr + info.offset;
+
+        // Load through ExpertCache (handles LRU eviction, VIP pinning, cache lookup)
+        if (self.expert_cache) |cache| {
+            // getOrLoad checks cache first, then loads if missing
+            const buffer = try cache.getOrLoad(
+                tensor_name,
+                data_ptr,
+                info.size,
+            );
+            return buffer;
+        }
+
+        // Fallback: create buffer directly (no caching)
+        const buffer = objc.deviceNewBufferWithBytes(
+            self.device,
+            data_ptr,
+            info.size,
+            objc.MTLResourceStorageModeShared,
+        ) orelse return error.BufferCreationFailed;
+
+        return buffer;
+    }
